from flask import Flask, jsonify, request
from datetime import datetime, timedelta

app = Flask(__name__)

# Assuming database layer is implemented separately
from database import TodoList, TodoItem

@app.route('/lists', methods=['GET'])
def get_all_lists():
    lists = TodoList.query.all()
    return jsonify([list.to_dict() for list in lists])

@app.route('/lists', methods=['POST'])
def create_list():
    data = request.get_json()
    new_list = TodoList(name=data['name'])
    new_list.save()
    return jsonify(new_list.to_dict()), 201

@app.route('/lists/<int:list_id>', methods=['GET'])
def get_list(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    return jsonify(list.to_dict())

@app.route('/lists/<int:list_id>', methods=['PUT'])
def update_list(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    data = request.get_json()
    list.name = data['name']
    list.save()
    return jsonify(list.to_dict())

@app.route('/lists/<int:list_id>', methods=['DELETE'])
def delete_list(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    list.delete()
    return jsonify({'message': 'List deleted'})

@app.route('/lists/<int:list_id>/items', methods=['GET'])
def get_list_items(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    items = list.items.all()
    return jsonify([item.to_dict() for item in items])

@app.route('/lists/<int:list_id>/items', methods=['POST'])
def create_item(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    data = request.get_json()
    new_item = TodoItem(name=data['name'], due_date=data['due_date'], list_id=list_id)
    new_item.save()
    return jsonify(new_item.to_dict()), 201

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['GET'])
def get_item(list_id, item_id):
    item = TodoItem.query.get(item_id)
    if item is None or item.list_id != list_id:
        return jsonify({'error': 'Item not found'}), 404
    return jsonify(item.to_dict())

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['PUT'])
def update_item(list_id, item_id):
    item = TodoItem.query.get(item_id)
    if item is None or item.list_id != list_id:
        return jsonify({'error': 'Item not found'}), 404
    data = request.get_json()
    item.name = data['name']
    item.due_date = data['due_date']
    item.save()
    return jsonify(item.to_dict())

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['DELETE'])
def delete_item(list_id, item_id):
    item = TodoItem.query.get(item_id)
    if item is None or item.list_id != list_id:
        return jsonify({'error': 'Item not found'}), 404
    item.delete()
    return jsonify({'message': 'Item deleted'})

@app.route('/lists/<int:list_id>/progress', methods=['GET'])
def get_progress(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    items = list.items.all()
    completed = [item for item in items if item.completed]
    return jsonify({'progress': len(completed) / len(items) * 100})

@app.route('/lists/<int:list_id>/reminders', methods=['GET'])
def get_reminders(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'error': 'List not found'}), 404
    items = list.items.all()
    due_items = [item for item in items if item.due_date <= datetime.now()]
    return jsonify([item.to_dict() for item in due_items])

if __name__ == '__main__':
    app.run(debug=True)

