from flask import Flask, jsonify, request
from datetime import datetime, timedelta

app = Flask(__name__)

# assuming database layer is implemented separately
from database import TodoList, TodoItem

@app.route('/lists', methods=['POST'])
def create_list():
    data = request.json
    new_list = TodoList(name=data['name'], description=data['description'])
    new_list.save()
    return jsonify({'id': new_list.id, 'name': new_list.name, 'description': new_list.description}), 201

@app.route('/lists', methods=['GET'])
def get_lists():
    lists = TodoList.query.all()
    output = []
    for list in lists:
        list_data = {'id': list.id, 'name': list.name, 'description': list.description}
        output.append(list_data)
    return jsonify(output)

@app.route('/lists/<id>', methods=['GET'])
def get_list(id):
    list = TodoList.query.get(id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    list_data = {'id': list.id, 'name': list.name, 'description': list.description}
    return jsonify(list_data)

@app.route('/lists/<id>', methods=['PUT'])
def update_list(id):
    list = TodoList.query.get(id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    data = request.json
    list.name = data['name']
    list.description = data['description']
    list.save()
    return jsonify({'id': list.id, 'name': list.name, 'description': list.description})

@app.route('/lists/<id>', methods=['DELETE'])
def delete_list(id):
    list = TodoList.query.get(id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    list.delete()
    return jsonify({'message': 'List deleted'})

@app.route('/lists/<list_id>/items', methods=['POST'])
def create_item(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    data = request.json
    new_item = TodoItem(name=data['name'], description=data['description'], due_date=data['due_date'], list_id=list_id)
    new_item.save()
    return jsonify({'id': new_item.id, 'name': new_item.name, 'description': new_item.description, 'due_date': new_item.due_date}), 201

@app.route('/lists/<list_id>/items', methods=['GET'])
def get_items(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    items = TodoItem.query.filter_by(list_id=list_id).all()
    output = []
    for item in items:
        item_data = {'id': item.id, 'name': item.name, 'description': item.description, 'due_date': item.due_date}
        output.append(item_data)
    return jsonify(output)

@app.route('/lists/<list_id>/items/<item_id>', methods=['GET'])
def get_item(list_id, item_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    item = TodoItem.query.get(item_id)
    if item is None or item.list_id != list_id:
        return jsonify({'message': 'Item not found'}), 404
    item_data = {'id': item.id, 'name': item.name, 'description': item.description, 'due_date': item.due_date}
    return jsonify(item_data)

@app.route('/lists/<list_id>/items/<item_id>', methods=['PUT'])
def update_item(list_id, item_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    item = TodoItem.query.get(item_id)
    if item is None or item.list_id != list_id:
        return jsonify({'message': 'Item not found'}), 404
    data = request.json
    item.name = data['name']
    item.description = data['description']
    item.due_date = data['due_date']
    item.save()
    return jsonify({'id': item.id, 'name': item.name, 'description': item.description, 'due_date': item.due_date})

@app.route('/lists/<list_id>/items/<item_id>', methods=['DELETE'])
def delete_item(list_id, item_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    item = TodoItem.query.get(item_id)
    if item is None or item.list_id != list_id:
        return jsonify({'message': 'Item not found'}), 404
    item.delete()
    return jsonify({'message': 'Item deleted'})

@app.route('/lists/<list_id>/progress', methods=['GET'])
def get_progress(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    items = TodoItem.query.filter_by(list_id=list_id).all()
    completed = 0
    total = 0
    for item in items:
        total += 1
        if item.completed:
            completed += 1
    progress = (completed / total) * 100 if total > 0 else 0
    return jsonify({'progress': progress})

@app.route('/lists/<list_id>/reminders', methods=['GET'])
def get_reminders(list_id):
    list = TodoList.query.get(list_id)
    if list is None:
        return jsonify({'message': 'List not found'}), 404
    items = TodoItem.query.filter_by(list_id=list_id).all()
    reminders = []
    for item in items:
        if item.due_date <= datetime.now():
            reminders.append({'id': item.id, 'name': item.name, 'description': item.description, 'due_date': item.due_date})
    return jsonify(reminders)

if __name__ == '__main__':
    app.run(debug=True)

