app = Flask(__name__)

# Assuming a pre-existing database layer
from database import TaskList, Task

# Initialize the database
db = TaskList()

# API endpoint to create a new task list
@app.route('/tasklists', methods=['POST'])
def create_task_list():
    data = request.get_json()
    task_list = TaskList(name=data['name'])
    db.add_task_list(task_list)
    return jsonify({'id': task_list.id, 'name': task_list.name}), 201

# API endpoint to get all task lists
@app.route('/tasklists', methods=['GET'])
def get_task_lists():
    task_lists = db.get_task_lists()
    return jsonify([{'id': task_list.id, 'name': task_list.name} for task_list in task_lists])

# API endpoint to get a specific task list
@app.route('/tasklists/<int:task_list_id>', methods=['GET'])
def get_task_list(task_list_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    return jsonify({'id': task_list.id, 'name': task_list.name, 'tasks': [{'id': task.id, 'name': task.name, 'deadline': task.deadline} for task in task_list.tasks]})

# API endpoint to update a task list
@app.route('/tasklists/<int:task_list_id>', methods=['PUT'])
def update_task_list(task_list_id):
    data = request.get_json()
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    task_list.name = data['name']
    db.update_task_list(task_list)
    return jsonify({'id': task_list.id, 'name': task_list.name})

# API endpoint to delete a task list
@app.route('/tasklists/<int:task_list_id>', methods=['DELETE'])
def delete_task_list(task_list_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    db.delete_task_list(task_list)
    return jsonify({'message': 'Task list deleted'})

# API endpoint to create a new task
@app.route('/tasklists/<int:task_list_id>/tasks', methods=['POST'])
def create_task(task_list_id):
    data = request.get_json()
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    task = Task(name=data['name'], deadline=data['deadline'])
    task_list.tasks.append(task)
    db.update_task_list(task_list)
    return jsonify({'id': task.id, 'name': task.name, 'deadline': task.deadline}), 201

# API endpoint to get all tasks in a task list
@app.route('/tasklists/<int:task_list_id>/tasks', methods=['GET'])
def get_tasks(task_list_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    return jsonify([{'id': task.id, 'name': task.name, 'deadline': task.deadline} for task in task_list.tasks])

# API endpoint to get a specific task
@app.route('/tasklists/<int:task_list_id>/tasks/<int:task_id>', methods=['GET'])
def get_task(task_list_id, task_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    task = next((task for task in task_list.tasks if task.id == task_id), None)
    if task is None:
        return jsonify({'error': 'Task not found'}), 404
    return jsonify({'id': task.id, 'name': task.name, 'deadline': task.deadline})

# API endpoint to update a task
@app.route('/tasklists/<int:task_list_id>/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_list_id, task_id):
    data = request.get_json()
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    task = next((task for task in task_list.tasks if task.id == task_id), None)
    if task is None:
        return jsonify({'error': 'Task not found'}), 404
    task.name = data['name']
    task.deadline = data['deadline']
    db.update_task_list(task_list)
    return jsonify({'id': task.id, 'name': task.name, 'deadline': task.deadline})

# API endpoint to delete a task
@app.route('/tasklists/<int:task_list_id>/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_list_id, task_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    task = next((task for task in task_list.tasks if task.id == task_id), None)
    if task is None:
        return jsonify({'error': 'Task not found'}), 404
    task_list.tasks.remove(task)
    db.update_task_list(task_list)
    return jsonify({'message': 'Task deleted'})

# API endpoint to get progress overview
@app.route('/tasklists/<int:task_list_id>/progress', methods=['GET'])
def get_progress(task_list_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    completed_tasks = [task for task in task_list.tasks if task.completed]
    total_tasks = len(task_list.tasks)
    progress = len(completed_tasks) / total_tasks * 100 if total_tasks > 0 else 0
    return jsonify({'progress': progress})

# API endpoint to get notifications
@app.route('/tasklists/<int:task_list_id>/notifications', methods=['GET'])
def get_notifications(task_list_id):
    task_list = db.get_task_list(task_list_id)
    if task_list is None:
        return jsonify({'error': 'Task list not found'}), 404
    notifications = []
    for task in task_list.tasks:
        if task.deadline < datetime.now():
            notifications.append({'task_id': task.id, 'message': 'Task is overdue'})
        elif task.deadline < datetime.now() + timedelta(days=7):
            notifications.append({'task_id': task.id, 'message': 'Task is approaching deadline'})
    return jsonify(notifications)

if __name__ == '__main__':
    app.run(debug=True)

